toml_template:
[[instances]]
address = "{{.username}}:{{.password}}@tcp({{.address}})/"
interval_times = 1
labels = { instance="{{.address}}" }

extra_status_metrics = {{.extra_status_metrics}}
extra_innodb_metrics = {{.extra_innodb_metrics}}
gather_slave_status = {{.gather_slave_status}}

interval = "{{.interval}}"
